const topics = [
  { id: 'obj-detect', label: 'Object Detection', query: 'object detection YOLO Faster R-CNN RetinaNet one-stage two-stage detection real-time visual recognition' },
  { id: 'image-recognition', label: 'Image Recognition', query: 'image recognition image classification visual recognition convolutional neural network CNN vision transformer ViT representation learning' },
  { id: 'video-ai', label: 'Video AI', query: 'video understanding action recognition temporal modeling video classification tracking 3D CNN transformer diffusion' },
  { id: 'edge-ai', label: 'Edge AI TinyML', query: 'edge machine learning TinyML embedded neural network model compression quantization pruning microcontroller on-device inference' },
  { id: 'llm-agents', label: 'LLM Agents', query: 'large language model agent autonomous tool use planning reasoning ReAct multi-agent orchestration' },
  { id: 'ai-ml-core', label: 'AI and Machine Learning', query: 'artificial intelligence machine learning deep learning reinforcement learning self-supervised learning foundation models' },
  { id: 'bioremediation', label: 'Bioremediation', query: 'bioremediation microbial contamination environmental cleanup biodegradation pollutant removal' },
  { id: 'bioenergy', label: 'Bioenergy', query: 'bioenergy biomass waste to energy biofuel anaerobic digestion renewable biological systems' },
  { id: 'bioengineering', label: 'Bioengineering', query: 'bioengineering synthetic biology metabolic engineering genetic circuit design bioprocess engineering' },
  { id: 'bioproduction', label: 'Bioproduction', query: 'bioproduction fermentation microbial biosynthesis industrial biotechnology upstream downstream processing' },
  { id: 'ai-ml-biosystems', label: 'AI and ML in Biosystems', query: 'machine learning artificial intelligence biosystems systems biology bioinformatics computational biology bioprocess optimization' }
];
const existingRows = $('Read Existing Professors (Annual)').all().map(item => item.json || {});
const existingIds = Array.from(new Set(existingRows.map(row => String(row['Profile URL'] || '').trim()).filter(Boolean)));
const existingNames = Array.from(new Set(existingRows.map(row => String(row['Full Name'] || '').toLowerCase().trim()).filter(Boolean)));
return topics.map(topic => ({ json: { ...topic, existingIds, existingNames } }));

function isoWeek(d = new Date()) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dayNum = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  const weekNo = Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
  return { year: date.getUTCFullYear(), week: weekNo };
}

const items = $input.all();
const sourceTopics = $('Prepare Topics (Annual)').all();
const rows = [];
const seenAuthorIds = new Set();
const topicCounts = {};

const now = new Date();
const iw = isoWeek(now);
const weekKey = `${iw.year}-${String(iw.week).padStart(2, '0')}`;

const ACTIVE_FROM_YEAR = 2025;
const PER_TOPIC_CAP = 60;
const MAX_NEW = 600;

for (let index = 0; index < items.length; index++) {
  const item = items[index];
  const source = sourceTopics[index]?.json || {};
  const existingIds = new Set((source.existingIds || []).map(String));
  const existingNames = new Set(
    (source.existingNames || []).map(name => String(name).toLowerCase().trim())
  );

  const topicId = String(source.id || '').trim();
  const topicLabel = String(source.label || '').trim();
  const results = item.json.results || [];

  if (!topicId || !topicLabel) continue;

  topicCounts[topicId] = topicCounts[topicId] || 0;

  for (const work of results) {
    if (rows.length >= MAX_NEW) break;
    if (topicCounts[topicId] >= PER_TOPIC_CAP) break;

    const publicationYear = Number(work.publication_year || 0);
    if (publicationYear < ACTIVE_FROM_YEAR) continue;

    for (const authorship of (work.authorships || [])) {
      if (rows.length >= MAX_NEW) break;
      if (topicCounts[topicId] >= PER_TOPIC_CAP) break;

      const author = authorship.author || {};
      const authorId = String(author.id || '').trim();
      const fullName = String(author.display_name || '').trim();
      const normalizedName = fullName.toLowerCase();

      if (!authorId || !fullName) continue;
      if (existingIds.has(authorId)) continue;
      if (existingNames.has(normalizedName)) continue;
      if (seenAuthorIds.has(authorId)) continue;

      const institution = (authorship.institutions || []).find(
        inst => inst.country_code === 'CA' && inst.type === 'education'
      );
      if (!institution) continue;

      seenAuthorIds.add(authorId);
      topicCounts[topicId] += 1;

      rows.push({
        json: {
          'Professor ID': `PROF-${iw.year}${String(iw.week).padStart(2, '0')}-${String(rows.length + 1).padStart(4, '0')}`,
          'Full Name': fullName,
          'Institution': institution.display_name || '',
          'Email': '',
          'Profile URL': authorId,
          'Topic ID': topicId,
          'Topic Label': topicLabel,
          'Relevance Score (1-10)': '',
          'Research Summary (AI)': '',
          'Top Paper Title': work.title || '',
          'Top Paper URL': work.id || '',
          'Top Paper Year': String(publicationYear || ''),
          'Profile Valid (Yes/No)': 'Pending',
          'Discovery Status': 'Discovered',
          'Discovery Date': now.toISOString().split('T')[0],
          'Discovery Week (YYYY-WW)': weekKey,
          'Outreach Status': 'Not Sent',
          'Last Draft Week (YYYY-WW)': '',
          'Last Contacted Date': '',
          'Rejection Reason': ''
        }
      });
    }

    if (rows.length >= MAX_NEW) break;
    if (topicCounts[topicId] >= PER_TOPIC_CAP) break;
  }

  if (rows.length >= MAX_NEW) break;
}

return rows;

function isoWeek(d = new Date()) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dayNum = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
