const rows = $input.all().map(item => item.json || {});
const iw = isoWeek(new Date());
const weekKey = `${iw.year}-${String(iw.week).padStart(2, '0')}`;
const topic = topics[(iw.week - 1) % topics.length];
const existingIds = rows.map(row => String(row['Profile URL'] || '').trim()).filter(Boolean);
const existingNames = rows.map(row => String(row['Full Name'] || '').toLowerCase().trim()).filter(Boolean);
const selected = rows
