  .sort((a, b) => Number(b['Relevance Score (1-10)'] || 0) - Number(a['Relevance Score (1-10)'] || 0))
  .slice(0, 2)
  .map(row => ({ ...row, _topicThisWeekId: topic.id, _topicThisWeekLabel: topic.label, _weekKey: weekKey, _selectionSource: 'sheet' }));
return [{ json: {
  _topicThisWeekId: topic.id,
  _topicThisWeekLabel: topic.label,
  _topicThisWeekQuery: topic.query,
  _weekKey: weekKey,
  _selected: selected,
  _missingCount: Math.max(0, 2 - selected.length),
  _needBackfill: selected.length < 2,
  _existingIds: existingIds,
  _existingNames: existingNames
} }];

const plan = $('Plan Weekly Selection').first().json;
const selected = Array.isArray(plan._selected) ? [...plan._selected] : [];
const chosenIds = new Set(selected.map(row => String(row['Profile URL'] || '')));
const existingIds = new Set((plan._existingIds || []).map(String));
const existingNames = new Set((plan._existingNames || []).map(String));
const results = $input.first().json.results || [];
let sequence = 1;

for (const work of results) {
