    selected.push({
      'Professor ID': `PROF-BF-${Date.now()}-${sequence++}` ,
      'Full Name': fullName,
      'Institution': institution.display_name || '',
      'Email': '',
      'Profile URL': authorId,
      'Topic ID': plan._topicThisWeekId,
      'Topic Label': plan._topicThisWeekLabel,
      'Relevance Score (1-10)': '',
      'Research Summary (AI)': '',
      'Top Paper Title': work.title || '',
      'Top Paper URL': work.id || '',
      'Top Paper Year': '',
      'Profile Valid (Yes/No)': 'Pending',
      'Discovery Status': 'Discovered',
      'Discovery Date': new Date().toISOString().split('T')[0],
      'Discovery Week (YYYY-WW)': plan._weekKey,
      'Outreach Status': 'Not Sent',
      'Last Draft Week (YYYY-WW)': '',
      'Last Contacted Date': '',
      'Rejection Reason': '',
      _topicThisWeekId: plan._topicThisWeekId,
      _topicThisWeekLabel: plan._topicThisWeekLabel,
      _weekKey: plan._weekKey,
      _selectionSource: 'backfill'
    });
    chosenIds.add(authorId);

    if (selected.length >= 2) break;
  }
  if (selected.length >= 2) break;
}

return selected.map(row => ({ json: row }));

const prof = $('Batch Weekly Candidates (1)').item.json;
const works = $input.item.json.results || [];

function rebuildAbstract(inv) {
  if (!inv) return '';
  return Object.entries(inv)
    .flatMap(([word, positions]) => positions.map(position => ({ word, position })))
    .sort((a, b) => a.position - b.position)
    .map(item => item.word)
    .join(' ')
    .substring(0, 900);
}

const topicId = prof['Topic ID'] || prof._topicThisWeekId || '';

const motivations = {
