const top = works[0] || {};
const paperTitle = top.title || prof['Top Paper Title'] || 'Untitled';
const paperYear = String(top.publication_year || prof['Top Paper Year'] || '');
const paperUrl = top.primary_location?.landing_page_url || top.id || prof['Top Paper URL'] || '';
const paperAbstract = rebuildAbstract(top.abstract_inverted_index);
const title = paperTitle.toLowerCase();
let heuristic = 6;
if (title.includes('object') || title.includes('detection') || title.includes('vision') || title.includes('video')) heuristic = 8;
if (title.includes('language') || title.includes('agent') || title.includes('llm')) heuristic = 8;
if (title.includes('bio') || title.includes('microbial') || title.includes('fermentation')) heuristic = 7;
if (title.includes('machine learning') || title.includes('artificial intelligence')) heuristic = Math.max(heuristic, 7);

return [{ json: { 
  ...prof, 
  _topPaperTitle: paperTitle, 
  _topPaperYear: paperYear, 
  _topPaperUrl: paperUrl, 
  _topPaperAbstract: paperAbstract, 
  _weeklySummary: `${prof['Institution'] || ''} | ${prof['_topicThisWeekLabel'] || prof['Topic Label'] || ''} | ${paperTitle}`, 
  _weeklyRelevanceScore: heuristic,
  _motivation: motivations[topicId] || motivations['ai-ml-core']
} }];

const raw = $input.item.json.text || $input.item.json.content || '';
const prof = $('Build Weekly Draft Context').item.json;
let parsed = {};
try {
  parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (error) {
  parsed = { subject: 'MSc Supervision Enquiry', body: raw.substring(0, 2500) };
}
return [{ json: { ...prof, _emailSubject: parsed.subject || 'MSc Supervision Enquiry', _emailBody: parsed.body || '' } }];

const wk = $('Batch Weekly Candidates (1)').first()?.json?._weekKey || $('Plan Weekly Selection').first()?.json?._weekKey || '';
const rows = $input.all().map(item => item.json || {});
const drafted = rows.filter(row => String(row['Created Week (YYYY-WW)'] || '') === wk);
const count = drafted.length;
if (count === 0) {
  return [{ json: { count: 0, html: `<html><body><p>No drafts created for week ${wk}. Sheet supply was low and backfill also returned no usable new professors.</p></body></html>` } }];
}
const cards = drafted.map((row, index) => `
  <div style="border:1px solid #e5e7eb;border-radius:10px;padding:14px;margin-bottom:12px;background:#fff;">
    <div style="font-size:12px;color:#6b7280;margin-bottom:4px;">Draft ${index + 1}</div>
    <div style="font-size:18px;font-weight:700;color:#111827;">${row['Professor Name'] || ''}</div>
    <div style="font-size:13px;color:#4b5563;margin-bottom:8px;">${row['Institution'] || ''}</div>
    <div><strong>Topic:</strong> ${row['Topic Label'] || ''}</div>
    <div><strong>Paper:</strong> ${row['Paper Referenced'] || ''}</div>
    ${row['Paper URL'] ? `<div><a href="${row['Paper URL']}">Open paper</a></div>` : ''}
    <div style="margin-top:8px;"><strong>Subject:</strong> ${row['Subject'] || ''}</div>
    <div style="margin-top:6px;color:#374151;">${String(row['Email Body'] || '').replace(/\n/g, '<br>')}</div>
  </div>
`).join('');
const html = `<!DOCTYPE html><html><body style="margin:0;padding:22px;background:#f3f4f6;font-family:Arial,sans-serif;color:#111827;">
<div style="max-width:860px;margin:0 auto;background:#fff;border-radius:14px;overflow:hidden;box-shadow:0 8px 30px rgba(0,0,0,.08);">
<div style="background:#1a3a2a;color:#fff;padding:24px 28px;">
<div style="font-size:12px;letter-spacing:1px;text-transform:uppercase;opacity:.85;">Weekly Outreach</div>
